using CommunityToolkit.Mvvm.ComponentModel;
using System.Collections.ObjectModel;

namespace KmgAssets.ViewModels;

public partial class AssetViewModel : ObservableObject
{
    [ObservableProperty]
    [NotifyCanExecuteChangedFor(nameof(SaveCommand))]
    private string _name = string.Empty;

    [ObservableProperty]
    private bool _isActive = true;

    [ObservableProperty]
    private bool _isBusy;

    public ObservableCollection<string> RecentAssets { get; } = new();
}

using CommunityToolkit.Mvvm.Input;

public partial class AssetViewModel : ObservableObject
{
    // ... поля выше

    [RelayCommand(CanExecute = nameof(CanSave))]
    private async Task SaveAsync()
    {
        IsBusy = true;
        try
        {
            await Task.Delay(500);  // имитация работы с БД
            RecentAssets.Insert(0, Name);
            Name = string.Empty;
        }
        finally
        {
            IsBusy = false;
        }
    }

    private bool CanSave() =>
        !string.IsNullOrWhiteSpace(Name) && !IsBusy;
}
